provider.example:
monaco.languages.registerHoverProvider('javascript', {
  provideHover(model, position, token) {
    const word = model.getWordAtPosition(position)
    if (!word) return null

    return {
      contents: [
        {
          value: '**console**()\n\nProvides access to the browser debugging console.',
          isTrusted: true,
          supportThemeIcons: true,
        }
      ],
      range: {
        startLineNumber: position.lineNumber,
        endLineNumber:   position.lineNumber,
        startColumn:     word.startColumn,
        endColumn:       word.endColumn,
      }
    }
  }
})

monaco.languages.registerDefinitionProvider('typescript', {
  provideDefinition(model, position, token) {
    const word = model.getWordAtPosition(position)
    if (!word) return null

    // Return single location
    return {
      uri:   monaco.Uri.parse('file:///src/utils.ts'),
      range: {
        startLineNumber: 42,
        startColumn:     1,
        endLineNumber:   42,
        endColumn:       20,
      }
    }

    // OR return LocationLink for richer experience
    return {
      originSelectionRange: {
        startLineNumber: position.lineNumber,
        startColumn:     word.startColumn,
        endLineNumber:   position.lineNumber,
        endColumn:       word.endColumn,
      },
      targetUri:            monaco.Uri.parse('file:///src/utils.ts'),
      targetRange: {
        startLineNumber: 42, startColumn: 1,
        endLineNumber:   50, endColumn:   1,
      },
      targetSelectionRange: {
        startLineNumber: 42, startColumn: 10,
        endLineNumber:   42, endColumn:   20,
      }
    }
  }
})

monaco.languages.registerCompletionItemProvider('typescript', {
  triggerCharacters: ['.', '"', "'", '/'],

  provideCompletionItems(model, position, context, token) {
    const word  = model.getWordUntilPosition(position)
    const range = {
      startLineNumber: position.lineNumber,
      endLineNumber:   position.lineNumber,
      startColumn:     word.startColumn,
      endColumn:       word.endColumn,
    }

    return {
      incomplete: false,
      suggestions: [
        // Snippet with tabstops
        {
          label:           'fn',
          kind:            15,   // Snippet
          insertText:      'function ${1:name}(${2:params}): ${3:void} {\n\t$0\n}',
          insertTextRules: 4,    // InsertAsSnippet
          documentation:   { value: '**function** snippet\n\nInserts a typed function declaration' },
          detail:          'snippet',
          range,
        },
        // Keyword
        {
          label:           'interface',
          kind:            14,   // Keyword
          insertText:      'interface ${1:Name} {\n\t$0\n}',
          insertTextRules: 4,
          documentation:   'Declare a TypeScript interface',
          detail:          'keyword',
          range,
        },
        // Built-in function
        {
          label:           'console.log',
          kind:            1,    // Function
          insertText:      'console.log(${1:value})',
          insertTextRules: 4,
          documentation:   { value: '**console.log**(value: any)\n\nLogs to browser console' },
          detail:          'built-in',
          preselect:       true,
          range,
        },
        // With CompletionItemLabel for richer display
        {
          label: {
            label:       'useState',
            detail:      '<S>(initialState: S)',
            description: 'react',
          },
          kind:            1,    // Function
          insertText:      'const [${1:state}, set${1/(.*)/${1:/capitalize}/}] = useState<${2:type}>(${3:initialValue})',
          insertTextRules: 4,
          documentation:   { value: '**useState**\n\nReact state hook' },
          detail:          'hook',
          range,
        },
      ]
    }
  },

  // Lazy load docs only when item selected
  resolveCompletionItem(item, token) {
    return {
      ...item,
      documentation: { value: `Detailed docs for **${item.label}**` }
    }
  }
})
